      "n": 33,
      "column": "left",
      "text": "Deewß irr/ kaß manni\napjohſch ar Spehku/ un darra\nmannus Zeltus bewainigus.\n"
    },
    {
      "n": 34,
      "column": "left",
      "text": "Wiꞥſch darra mannas\nRuhjas lihosas tahm Erſchku-\nMahtehn/ un eezell manni us\nmanneem Augſtumeem.\n"
    },
    {
      "n": 35,
      "column": "left",
      "text": "Wiꞥſch mahza mannu\nRohku farcht/ ta ka mans El-\nkons warra Stohpus falausa.\n"
    },
    {
      "n": 36,
      "column": "left",
      "text": "Un tu dohd man arri tahs\npreekſchturramas Bruzzas ta-\nwaz Pestit(chanas/ un tawa lab-\nba Rohka atspeesch manni/ un\n"
    },
    {
      "n": 37,
      "column": "left",
      "text": "tawa Paſemmoschana manni Pillis.\nva-augſtina.\nTu eſſi manneem Soh.\nkeim plattu Weetu appatſch\nmannim darriß/ ka manni\nKrumſii ne irr ſlihdeifcht.\n"
    },
    {
      "n": 38,
      "column": "left",
      "text": "Es dſihſchohs mannam\nEenadneekam pakkat/ un ne at-\ngreesifchohs/ pirins es tohs buh-\nfchu iſdeldejs.\n"
    },
    {
      "n": 39,
      "column": "left",
      "text": "Es ſadauſichu tohs/ ka\ntee ne warrehs zeltees/ teem ja-\nfrith appatſch mannabin Rah\njahm.\n"
    },
    {
      "n": 40,
      "column": "left",
      "text": "Jo tu apjohſ mann ar\nSpehku us Karzu/ tn notohzi\nappatſch mannim/ kaß prett\nmanni zeltahs.\n"
    },
    {
      "n": 41,
      "column": "left",
      "text": "Tu leeß manmus Eenaid-\nneekus preekſch mannim behat/\nun manmus Nihdetajus iſnihzi\nnaju es.\n"
    },
    {
      "n": 42,
      "column": "left",
      "text": "Tee brehz/ bet Atpeſtita-\n"
    },
    {
      "n": 43,
      "column": "right",
      "text": "Es ſagruhdiſchu tohs\nBihſchlus preeſch ta Wehja/\nno-abrdiſchu tohs ka Dubtus\nEſlahm.\n"
    },
    {
      "n": 44,
      "column": "right",
      "text": "Tu iſglabb manni no\nLauschu Kildahn/ tu eezell ma-\nni par Galwu ſarp teem Pag-\nneem/ tee Laudis/ ko es ne\nſinnu/ kalpo man.\n"
    },
    {
      "n": 45,
      "column": "right",
      "text": "Tee paklaufa manni\npaklaufigahm Auſim/ ſwe-\nBehrni irr pee man Mellufti ta-\npuſchi.\n"
    },
    {
      "n": 46,
      "column": "right",
      "text": "Sweſcht Behrni irr\nnihkuſchi/ un gohrahs fan\n"
    },
    {
      "n": 47,
      "column": "right",
      "text": "Tas KUNGS dfih-\nun flawehts lai irr mans\nſwerums/ un augſti flawe-\nlai irr tas Deews mannas\nſtischanas.\n"
    },
    {
      "n": 48,
      "column": "right",
      "text": "Tas STIPRA\nDEWS/ kaß man Atreepſ-\nnas dohd/ un Laudis appa-\nmannim pamett.\n"
    },
    {
      "n": 49,
      "column": "right",
      "text": "Kaß manni iſranij\nmanneem Eenadneekem/ ir-\npa-augſtina manni pahr tee-\nkaß prett manni zeltahs/ tu-\nglahb manni no Warras-D-\nritajeem.\n"
    },
    {
      "n": 50,
      "column": "right",
      "text": "Tapehz gribbu eß ten\nKUNGS! flaweht ſarp t-\nPaganeem/ un tawan W-\ndam dſeedaht.\n"
    },
    {
      "n": 51,
      "column": "right",
      "text": "Kaß taiva Rehnina P-\nichanas pa-augſtina/ un S-\nlaſtibu parahta tawan S-\ndit\n"
    }
  ],
